20	// NewPersonaLoader creates a new persona loader with the default personas directory
21	func NewPersonaLoader(workingDir string) PersonaLoader {
22		// Use the config system to get the library path, then append personas
23		cfg, err := config.LoadWithWorkingDir(workingDir)
24		var personasDir string
25		if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
26			// Fallback to a reasonable default if there's an error
27			homeDir, _ := os.UserHomeDir()
28			personasDir = filepath.Join(homeDir, ".ddx", "plugins", "ddx", "personas")
29		} else {
30			personasDir = filepath.Join(cfg.Library.Path, "personas")
31		}
32	
33		return &PersonaLoaderImpl{
34			personasDir: personasDir,
35		}
36	}
37	
38	// NewPersonaLoaderWithDir creates a new persona loader with a specific directory
39	func NewPersonaLoaderWithDir(dir string) PersonaLoader {
40		return &PersonaLoaderImpl{
41			personasDir: dir,
42		}
43	}
