45	// LoadPersona loads a persona by name from the file system
46	func (l *PersonaLoaderImpl) LoadPersona(name string) (*Persona, error) {
47		if name == "" {
48			return nil, NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
49		}
50	
51		// Construct file path
52		fileName := name + PersonaFileExtension
53		filePath := filepath.Join(l.personasDir, fileName)
54	
55		// Check if file exists
56		if !fileExists(filePath) {
57			return nil, NewPersonaError(ErrorPersonaNotFound,
58				fmt.Sprintf("persona '%s' not found at %s", name, filePath), nil)
59		}
60	
61		// Read file content
62		content, err := os.ReadFile(filePath)
63		if err != nil {
64			return nil, NewPersonaError(ErrorFileOperation,
65				fmt.Sprintf("failed to read persona file %s", filePath), err)
66		}
67	
68		// Check file size
69		if len(content) > MaxPersonaFileSize {
70			return nil, NewPersonaError(ErrorValidation,
71				fmt.Sprintf("persona file %s exceeds maximum size of %d bytes", fileName, MaxPersonaFileSize), nil)
72		}
73	
74		// Parse persona from content
75		persona, err := parsePersona(content)
76		if err != nil {
77			return nil, NewPersonaError(ErrorInvalidPersona,
78				fmt.Sprintf("failed to parse persona %s", name), err)
79		}
80	
81		return persona, nil
82	}
83	
84	// ListPersonas returns all available personas
85	func (l *PersonaLoaderImpl) ListPersonas() ([]*Persona, error) {
86		if !dirExists(l.personasDir) {
87			return []*Persona{}, nil // Return empty list if directory doesn't exist
88		}
89	
90		// Read directory contents
91		entries, err := os.ReadDir(l.personasDir)
92		if err != nil {
93			return nil, NewPersonaError(ErrorFileOperation,
94				fmt.Sprintf("failed to read personas directory %s", l.personasDir), err)
95		}
96	
97		var personas []*Persona
98	
99		// Process each markdown file
100		for _, entry := range entries {
101			if entry.IsDir() {
102				continue
103			}
104	
105			// Only process .md files
106			if !strings.HasSuffix(entry.Name(), PersonaFileExtension) {
107				continue
108			}
109	
110			// Skip README.md and other documentation files
111			if entry.Name() == "README.md" || entry.Name() == "readme.md" {
112				continue
113			}
114	
115			// Extract persona name from filename
116			personaName := strings.TrimSuffix(entry.Name(), PersonaFileExtension)
117	
118			// Load persona (this will handle validation)
119			persona, err := l.LoadPersona(personaName)
120			if err != nil {
121				// Log warning but continue processing other personas
122				_, _ = fmt.Fprintf(os.Stderr, "Warning: Skipping invalid persona %s: %v\n", entry.Name(), err)
123				continue
124			}
125	
126			personas = append(personas, persona)
127		}
128	
129		return personas, nil
130	}
