132	// FindByRole returns personas that can fulfill the specified role
133	func (l *PersonaLoaderImpl) FindByRole(role string) ([]*Persona, error) {
134		if role == "" {
135			return nil, NewPersonaError(ErrorValidation, "role cannot be empty", nil)
136		}
137	
138		allPersonas, err := l.ListPersonas()
139		if err != nil {
140			return nil, err
141		}
142	
143		var matchingPersonas []*Persona
144	
145		for _, persona := range allPersonas {
146			for _, personaRole := range persona.Roles {
147				if personaRole == role {
148					matchingPersonas = append(matchingPersonas, persona)
149					break // Avoid duplicate entries
150				}
151			}
152		}
153	
154		return matchingPersonas, nil
155	}
