157	// FindByTags returns personas that have all the specified tags
158	func (l *PersonaLoaderImpl) FindByTags(tags []string) ([]*Persona, error) {
159		if len(tags) == 0 {
160			return nil, NewPersonaError(ErrorValidation, "at least one tag must be specified", nil)
161		}
162	
163		allPersonas, err := l.ListPersonas()
164		if err != nil {
165			return nil, err
166		}
167	
168		var matchingPersonas []*Persona
169	
170		for _, persona := range allPersonas {
171			if hasAllTags(persona.Tags, tags) {
172				matchingPersonas = append(matchingPersonas, persona)
173			}
174		}
175	
176		return matchingPersonas, nil
177	}
