179	// parsePersona parses a persona from markdown content with YAML frontmatter
180	func parsePersona(content []byte) (*Persona, error) {
181		// Split frontmatter and content
182		frontmatter, markdownContent, err := splitFrontmatter(content)
183		if err != nil {
184			return nil, err
185		}
186	
187		// Parse YAML frontmatter
188		var persona Persona
189		if err := yaml.Unmarshal(frontmatter, &persona); err != nil {
190			return nil, NewPersonaError(ErrorInvalidPersona, "failed to parse YAML frontmatter", err)
191		}
192	
193		// Set content
194		persona.Content = string(markdownContent)
195	
196		// Validate required fields
197		if err := validatePersona(&persona); err != nil {
198			return nil, err
199		}
200	
201		return &persona, nil
202	}
203	
204	// splitFrontmatter splits YAML frontmatter from markdown content
205	func splitFrontmatter(content []byte) (frontmatter []byte, markdown []byte, err error) {
206		scanner := bufio.NewScanner(bytes.NewReader(content))
207	
208		var lines []string
209		for scanner.Scan() {
210			lines = append(lines, scanner.Text())
211		}
212	
213		if len(lines) < 2 {
214			return nil, nil, NewPersonaError(ErrorInvalidPersona, "file too short to contain frontmatter", nil)
215		}
216	
217		// Check for frontmatter start
218		if lines[0] != "---" {
219			return nil, nil, NewPersonaError(ErrorInvalidPersona, "missing YAML frontmatter (must start with ---)", nil)
220		}
221	
222		// Find frontmatter end
223		frontmatterEnd := -1
224		for i := 1; i < len(lines); i++ {
225			if lines[i] == "---" {
226				frontmatterEnd = i
227				break
228			}
229		}
230	
231		if frontmatterEnd == -1 {
232			return nil, nil, NewPersonaError(ErrorInvalidPersona, "unclosed YAML frontmatter (missing closing ---)", nil)
233		}
234	
235		// Extract frontmatter (excluding delimiters)
236		frontmatterLines := lines[1:frontmatterEnd]
237		frontmatter = []byte(strings.Join(frontmatterLines, "\n"))
238	
239		// Extract markdown content (after frontmatter)
240		var markdownLines []string
241		if frontmatterEnd+1 < len(lines) {
242			markdownLines = lines[frontmatterEnd+1:]
243			// Remove leading empty lines
244			for len(markdownLines) > 0 && strings.TrimSpace(markdownLines[0]) == "" {
245				markdownLines = markdownLines[1:]
246			}
247		}
248	
249		markdown = []byte(strings.Join(markdownLines, "\n"))
250	
251		return frontmatter, markdown, nil
252	}
253	
254	// validatePersona validates that a persona has all required fields
255	func validatePersona(persona *Persona) error {
256		if persona.Name == "" {
257			return NewPersonaError(ErrorValidation, "persona name is required", nil)
258		}
259	
260		if len(persona.Roles) == 0 {
261			return NewPersonaError(ErrorValidation, "persona must have at least one role", nil)
262		}
263	
264		if persona.Description == "" {
265			return NewPersonaError(ErrorValidation, "persona description is required", nil)
266		}
267	
268		// Validate limits
269		if len(persona.Roles) > MaxRolesPerPersona {
270			return NewPersonaError(ErrorValidation,
271				fmt.Sprintf("persona cannot have more than %d roles", MaxRolesPerPersona), nil)
272		}
273	
274		if len(persona.Tags) > MaxTagsPerPersona {
275			return NewPersonaError(ErrorValidation,
276				fmt.Sprintf("persona cannot have more than %d tags", MaxTagsPerPersona), nil)
277		}
278	
279		// Ensure tags is not nil (should be empty slice if not provided)
280		if persona.Tags == nil {
281			persona.Tags = []string{}
282		}
283	
284		return nil
285	}
286	
287	// hasAllTags checks if a persona has all the specified tags
288	func hasAllTags(personaTags []string, requiredTags []string) bool {
289		personaTagMap := make(map[string]bool)
290		for _, tag := range personaTags {
291			personaTagMap[tag] = true
292		}
293	
294		for _, requiredTag := range requiredTags {
295			if !personaTagMap[requiredTag] {
296				return false
297			}
298		}
299	
300		return true
301	}
302	
303	// fileExists checks if a file exists
304	func fileExists(filePath string) bool {
305		_, err := os.Stat(filePath)
306		return !os.IsNotExist(err)
307	}
308	
309	// dirExists checks if a directory exists
310	func dirExists(dirPath string) bool {
311		info, err := os.Stat(dirPath)
312		if os.IsNotExist(err) {
313			return false
314		}
315		return info.IsDir()
316	}
