30	// deprecatedPersonas lists personas from the pre-consolidation roster
31	// (pre-FEAT-011 Phase 3) that have been removed. The map is kept as empty
32	// to preserve the function signatures for future use if needed.
33	var deprecatedPersonas = map[string]string{}
34	
35	// deprecationNoticeFor returns a human-readable warning string (without
36	// a newline) for a deprecated persona, or empty if the name is current.
37	// Callers write it to stderr themselves so the caller controls framing.
38	func deprecationNoticeFor(name string) string {
39		replacement, deprecated := deprecatedPersonas[name]
40		if !deprecated {
41			return ""
42		}
43		if replacement != "" {
44			return fmt.Sprintf("warning: persona %q is deprecated and will be removed in a future release; use %q instead", name, replacement)
45		}
46		return fmt.Sprintf("warning: persona %q is deprecated and will be removed in a future release with no direct replacement; see library/personas/README.md for the current 5-persona roster", name)
47	}
