82	// runPersonaWithWorkingDir implements the persona command logic with working directory support
83	func runPersonaWithWorkingDir(cmd *cobra.Command, args []string, workingDir string) error {
84		// Extract flags from cobra.Command
85		listFlag, _ := cmd.Flags().GetBool("list")
86		showFlag, _ := cmd.Flags().GetString("show")
87		bindFlag, _ := cmd.Flags().GetString("bind")
88		roleFlag, _ := cmd.Flags().GetString("role")
89		roleFilter, _ := cmd.Flags().GetString("role")
90		tagFilter, _ := cmd.Flags().GetString("tag")
91	
92		// Handle subcommands
93		if len(args) > 0 {
94			switch args[0] {
95			case "list":
96				personas, err := personaList(workingDir, roleFilter, tagFilter)
97				if err != nil {
98					return err
99				}
100				return displayPersonaList(cmd, personas)
101			case "show":
102				if len(args) < 2 {
103					return fmt.Errorf("persona name required")
104				}
105				persona, err := personaShow(workingDir, args[1])
106				if err != nil {
107					return err
108				}
109				return displayPersona(cmd, persona)
110			case "bind":
111				if len(args) < 3 {
112					return fmt.Errorf("role and persona name required")
113				}
114				err := personaBind(workingDir, args[1], args[2])
115				if err != nil {
116					return err
117				}
118				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Bound role '%s' to persona '%s'\n", args[1], args[2])
119				return nil
120			case "load":
121				loadedPersonas, err := personaLoad(workingDir, args[1:]...)
122				if err != nil {
123					return err
124				}
125				return displayLoadResult(cmd, args[1:], loadedPersonas)
126			case "bindings":
127				bindings, err := personaBindings(workingDir)
128				if err != nil {
129					return err
130				}
131				return displayBindings(cmd, bindings)
132			case "status":
133				status, err := personaStatus(workingDir)
134				if err != nil {
135					return err
136				}
137				return displayPersonaStatus(cmd, status)
138			}
139		}
140	
141		// Handle flags
142		if listFlag {
143			personas, err := personaList(workingDir, roleFilter, tagFilter)
144			if err != nil {
145				return err
146			}
147			return displayPersonaList(cmd, personas)
148		}
149	
150		if showFlag != "" {
151			persona, err := personaShow(workingDir, showFlag)
152			if err != nil {
153				return err
154			}
155			return displayPersona(cmd, persona)
156		}
157	
158		if bindFlag != "" && roleFlag != "" {
159			err := personaBind(workingDir, roleFlag, bindFlag)
160			if err != nil {
161				return err
162			}
163			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Bound role '%s' to persona '%s'\n", roleFlag, bindFlag)
164			return nil
165		}
166	
167		// Show help when no flags or args provided
168		return cmd.Help()
169	}
