171	// displayPersonaList displays the list of personas to the user
172	func displayPersonaList(cmd *cobra.Command, personas []PersonaInfo) error {
173		if len(personas) == 0 {
174			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No personas found")
175			return nil
176		}
177	
178		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Available Personas:")
179		_, _ = fmt.Fprintln(cmd.OutOrStdout())
180	
181		// Create tabwriter for aligned output
182		w := tabwriter.NewWriter(cmd.OutOrStdout(), 0, 0, 2, ' ', 0)
183		_, _ = fmt.Fprintln(w, "PERSONA\tROLE\tDESCRIPTION")
184		_, _ = fmt.Fprintln(w, "-------\t----\t-----------")
185	
186		var deprecatedSeen []string
187		for _, persona := range personas {
188			roleStr := "general"
189			if len(persona.Roles) > 0 {
190				roleStr = persona.Roles[0]
191			}
192			displayName := persona.Name
193			if _, deprecated := deprecatedPersonas[persona.Name]; deprecated {
194				displayName = persona.Name + " (deprecated)"
195				deprecatedSeen = append(deprecatedSeen, persona.Name)
196			}
197			_, _ = fmt.Fprintf(w, "%s\t%s\t%s\n", displayName, roleStr, persona.Description)
198		}
199	
200		_ = w.Flush()
201	
202		// Emit a single aggregated deprecation notice on stderr so piped stdout
203		// stays clean. Individual notices go to stderr only when show/bind
204		// targets one deprecated persona directly.
205		for _, name := range deprecatedSeen {
206			if notice := deprecationNoticeFor(name); notice != "" {
207				_, _ = fmt.Fprintln(os.Stderr, notice)
208			}
209		}
210		return nil
211	}
