213	// displayPersona displays a single persona to the user
214	func displayPersona(cmd *cobra.Command, persona *PersonaInfo) error {
215		if persona == nil {
216			return fmt.Errorf("persona not found")
217		}
218	
219		// Emit the deprecation notice to stderr before the persona body so the
220		// warning is visible even when the caller pipes stdout elsewhere.
221		if notice := deprecationNoticeFor(persona.Name); notice != "" {
222			_, _ = fmt.Fprintln(os.Stderr, notice)
223		}
224	
225		// Parse metadata from content
226		metadata := parsePersonaMetadata(persona.Content)
227		if metadata != nil {
228			// Display formatted metadata
229			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Name: %s\n", metadata.Name)
230			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Roles: %s\n", strings.Join(metadata.Roles, ", "))
231			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Description: %s\n", metadata.Description)
232			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "Tags: %s\n", strings.Join(metadata.Tags, ", "))
233	
234			// Display content after frontmatter
235			lines := strings.Split(persona.Content, "\n")
236			contentStart := 0
237			foundEnd := false
238			for i, line := range lines {
239				if i > 0 && line == "---" {
240					contentStart = i + 1
241					foundEnd = true
242					break
243				}
244			}
245			if foundEnd && contentStart < len(lines) {
246				_, _ = fmt.Fprintln(cmd.OutOrStdout())
247				_, _ = fmt.Fprint(cmd.OutOrStdout(), strings.Join(lines[contentStart:], "\n"))
248			}
249		} else {
250			// No frontmatter, display raw content
251			_, _ = fmt.Fprint(cmd.OutOrStdout(), persona.Content)
252		}
253		return nil
254	}
