279	// displayPersonaStatus displays persona status to the user
280	func displayPersonaStatus(cmd *cobra.Command, status PersonaStatus) error {
281		if !status.HasCLAUDEFile {
282			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No CLAUDE.md file found - no personas loaded")
283			return nil
284		}
285	
286		if len(status.LoadedPersonas) > 0 {
287			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "Loaded Personas:")
288			for i, persona := range status.LoadedPersonas {
289				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "  - %s (%s)\n", persona, status.LoadedRoles[i])
290			}
291		} else {
292			_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No personas currently loaded")
293		}
294	
295		if status.BindingsCount > 0 {
296			_, _ = fmt.Fprintf(cmd.OutOrStdout(), "\n%d persona binding(s) configured\n", status.BindingsCount)
297		}
298	
299		return nil
300	}
