302	// displayLoadResult displays the result of loading personas
303	func displayLoadResult(cmd *cobra.Command, requestedPersonas []string, loadedPersonas []string) error {
304		if len(requestedPersonas) > 0 {
305			// Specific personas loaded
306			if len(loadedPersonas) == 1 {
307				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Loaded persona '%s' into CLAUDE.md\n", loadedPersonas[0])
308			} else {
309				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Loaded %d personas into CLAUDE.md\n", len(loadedPersonas))
310			}
311		} else {
312			// All bound personas loaded
313			if len(loadedPersonas) > 0 {
314				_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Loaded %d personas (%s) into CLAUDE.md\n",
315					len(loadedPersonas), strings.Join(loadedPersonas, ", "))
316			} else {
317				_, _ = fmt.Fprintln(cmd.OutOrStdout(), "No bound personas to load")
318			}
319		}
320		return nil
321	}
