326	
327	// personaList returns a list of available personas
328	func personaList(workingDir string, roleFilter, tagFilter string) ([]PersonaInfo, error) {
329		// Get library path
330		libPath, err := getPersonaLibraryPath(workingDir)
331		if err != nil {
332			return nil, fmt.Errorf("failed to get library path: %w", err)
333		}
334	
335		personasDir := filepath.Join(libPath, "personas")
336	
337		// Check if personas directory exists
338		if _, err := os.Stat(personasDir); os.IsNotExist(err) {
339			return []PersonaInfo{}, nil
340		}
341	
342		// Read personas directory
343		entries, err := os.ReadDir(personasDir)
344		if err != nil {
345			return nil, fmt.Errorf("failed to read personas directory: %w", err)
346		}
347	
348		var personas []PersonaInfo
349	
350		for _, entry := range entries {
351			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".md") {
352				continue
353			}
354	
355			name := strings.TrimSuffix(entry.Name(), ".md")
356			filePath := filepath.Join(personasDir, entry.Name())
357	
358			// Read and parse persona file
359			content, err := os.ReadFile(filePath)
360			if err != nil {
361				continue
362			}
363	
364			// Parse frontmatter
365			metadata := parsePersonaMetadata(string(content))
366			if metadata == nil {
367				// Fallback to simple parsing
368				metadata = &PersonaMetadata{
369					Name:        name,
370					Roles:       []string{"general"},
371					Description: name,
372				}
373			}
374	
375			// Apply role filter
376			if roleFilter != "" {
377				hasRole := false
378				for _, role := range metadata.Roles {
379					if role == roleFilter {
380						hasRole = true
381						break
382					}
383				}
384				if !hasRole {
385					continue
386				}
387			}
388	
389			// Apply tag filter
390			if tagFilter != "" {
391				hasTag := false
392				for _, tag := range metadata.Tags {
393					if tag == tagFilter {
394						hasTag = true
395						break
396					}
397				}
398				if !hasTag {
399					continue
400				}
401			}
402	
403			// Create persona info
404			personaInfo := PersonaInfo{
405				Name:        name,
406				Roles:       metadata.Roles,
407				Description: metadata.Description,
408				Tags:        metadata.Tags,
409				Content:     string(content),
410				FilePath:    filePath,
411			}
412			personas = append(personas, personaInfo)
413		}
414	
415		return personas, nil
416	}
