459	// personaBind binds a role to a persona
460	func personaBind(workingDir string, role, personaName string) error {
461		// Check if persona exists first
462		libPath, err := getPersonaLibraryPath(workingDir)
463		if err != nil {
464			return fmt.Errorf("failed to get library path: %w", err)
465		}
466	
467		personaPath := filepath.Join(libPath, "personas", personaName+".md")
468		if _, err := os.Stat(personaPath); os.IsNotExist(err) {
469			return fmt.Errorf("persona '%s' not found at path %s", personaName, personaPath)
470		}
471	
472		// Emit a stderr deprecation warning when binding a role to a deprecated
473		// persona. Non-fatal — users migrate on their own timeline during the
474		// deprecation window.
475		if notice := deprecationNoticeFor(personaName); notice != "" {
476			_, _ = fmt.Fprintln(os.Stderr, notice)
477		}
478	
479		// Load only the local config file to preserve structure
480		configPath := ".ddx/config.yaml"
481		if workingDir != "" {
482			configPath = filepath.Join(workingDir, ".ddx/config.yaml")
483		}
484	
485		// Read current config as raw YAML node to preserve structure
486		data, err := os.ReadFile(configPath)
487		if err != nil {
488			return fmt.Errorf("failed to read config file %s: %w", configPath, err)
489		}
490	
491		var rootNode yaml.Node
492		if err := yaml.Unmarshal(data, &rootNode); err != nil {
493			return fmt.Errorf("failed to parse config: %w", err)
494		}
495	
496		// Find or create persona_bindings section
497		if err := addPersonaBindingToNode(&rootNode, role, personaName); err != nil {
498			return fmt.Errorf("failed to add persona binding: %w", err)
499		}
500	
501		// Write back to file
502		newData, err := yaml.Marshal(&rootNode)
503		if err != nil {
504			return fmt.Errorf("failed to marshal config: %w", err)
505		}
506	
507		if err := os.WriteFile(configPath, newData, 0644); err != nil {
508			return fmt.Errorf("failed to write config file %s: %w", configPath, err)
509		}
510	
511		return nil
512	}
