540	func personaStatus(workingDir string) (PersonaStatus, error) {
541		claudePath := "CLAUDE.md"
542		if workingDir != "" {
543			claudePath = filepath.Join(workingDir, "CLAUDE.md")
544		}
545	
546		status := PersonaStatus{
547			HasCLAUDEFile: false,
548		}
549	
550		// Check if CLAUDE.md exists
551		if _, err := os.Stat(claudePath); os.IsNotExist(err) {
552			return status, nil
553		}
554	
555		status.HasCLAUDEFile = true
556	
557		// Read CLAUDE.md
558		content, err := os.ReadFile(claudePath)
559		if err != nil {
560			return status, fmt.Errorf("failed to read CLAUDE.md: %w", err)
561		}
562	
563		// Parse loaded personas
564		claudeStr := string(content)
565		if strings.Contains(claudeStr, "<!-- PERSONAS:START -->") &&
566			strings.Contains(claudeStr, "<!-- PERSONAS:END -->") {
567			// Extract persona section
568			startIdx := strings.Index(claudeStr, "<!-- PERSONAS:START -->")
569			endIdx := strings.Index(claudeStr, "<!-- PERSONAS:END -->")
570			if startIdx != -1 && endIdx != -1 && endIdx > startIdx {
571				personaSection := claudeStr[startIdx:endIdx]
572	
573				// Parse loaded personas
574				lines := strings.Split(personaSection, "\n")
575				for _, line := range lines {
576					if strings.HasPrefix(line, "### ") {
577						// Parse role and persona from header
578						header := strings.TrimPrefix(line, "### ")
579						parts := strings.Split(header, ": ")
580						if len(parts) == 2 {
581							status.LoadedRoles = append(status.LoadedRoles, parts[0])
582							status.LoadedPersonas = append(status.LoadedPersonas, parts[1])
583						}
584					}
585				}
586			}
587		}
588	
589		// Get bindings count
590		cfg, err := loadPersonaConfig(workingDir)
591		if err == nil && cfg.PersonaBindings != nil {
592			status.BindingsCount = len(cfg.PersonaBindings)
593		}
594	
595		return status, nil
596	}
