598	// personaLoad loads personas into CLAUDE.md
599	func personaLoad(workingDir string, personas ...string) ([]string, error) {
600		// Always check if config file exists (new format)
601		configPath := ".ddx/config.yaml"
602		if workingDir != "" {
603			configPath = filepath.Join(workingDir, ".ddx/config.yaml")
604		}
605		if _, err := os.Stat(configPath); os.IsNotExist(err) {
606			return nil, fmt.Errorf("No .ddx/config.yaml configuration found")
607		}
608	
609		// Load config to get persona bindings
610		cfg, err := loadPersonaConfig(workingDir)
611		if err != nil {
612			return nil, fmt.Errorf("failed to load configuration: %w", err)
613		}
614	
615		// Get library path
616		libPath, err := getPersonaLibraryPath(workingDir)
617		if err != nil {
618			return nil, fmt.Errorf("failed to get library path: %w", err)
619		}
620	
621		// Read CLAUDE.md if it exists
622		claudePath := "CLAUDE.md"
623		if workingDir != "" {
624			claudePath = filepath.Join(workingDir, "CLAUDE.md")
625		}
626	
627		var claudeContent string
628		if data, err := os.ReadFile(claudePath); err == nil {
629			claudeContent = string(data)
630		} else {
631			// Create new CLAUDE.md
632			claudeContent = "# CLAUDE.md\n\nProject guidance for my application."
633		}
634	
635		// Remove existing persona section if present
636		startMarker := "<!-- PERSONAS:START -->"
637		endMarker := "<!-- PERSONAS:END -->"
638		startIdx := strings.Index(claudeContent, startMarker)
639		if startIdx != -1 {
640			endIdx := strings.Index(claudeContent, endMarker)
641			if endIdx != -1 {
642				claudeContent = claudeContent[:startIdx] + claudeContent[endIdx+len(endMarker):]
643			}
644		}
645	
646		// Build persona content
647		var personaSection strings.Builder
648		personaSection.WriteString("\n" + startMarker + "\n")
649		personaSection.WriteString("## Active Personas\n\n")
650	
651		// Track loaded personas
652		loadedPersonas := []string{}
653	
654		// If specific personas requested, load those; otherwise load all bound personas
655		if len(personas) > 0 {
656			// Load specific personas
657			for _, personaName := range personas {
658				personaPath := filepath.Join(libPath, "personas", personaName+".md")
659				if content, err := os.ReadFile(personaPath); err == nil {
660					// Validate persona content if it has frontmatter
661					if err := validatePersonaContent(string(content), personaName); err != nil {
662						return nil, err
663					}
664					// Just add the content - personas have their own titles
665					personaSection.WriteString(string(content) + "\n")
666					loadedPersonas = append(loadedPersonas, personaName)
667				} else if os.IsNotExist(err) {
668					return nil, fmt.Errorf("persona '%s' not found", personaName)
669				}
670			}
671		} else {
672			// Load all bound personas from config
673			if cfg.PersonaBindings != nil {
674				for role, personaName := range cfg.PersonaBindings {
675					personaPath := filepath.Join(libPath, "personas", personaName+".md")
676					if content, err := os.ReadFile(personaPath); err == nil {
677						// Validate persona content if it has frontmatter
678						if err := validatePersonaContent(string(content), personaName); err != nil {
679							return nil, err
680						}
681						// Add role header with proper capitalization
682						caser := cases.Title(language.English)
683						capitalizedRole := caser.String(strings.ReplaceAll(role, "-", " "))
684						personaSection.WriteString(fmt.Sprintf("### %s: %s\n", capitalizedRole, personaName))
685						personaSection.WriteString(string(content) + "\n")
686						loadedPersonas = append(loadedPersonas, personaName)
687					}
688				}
689			}
690		}
691	
692		personaSection.WriteString(endMarker + "\n")
693	
694		// Append persona section to CLAUDE.md
695		claudeContent += personaSection.String()
696	
697		// Write updated CLAUDE.md
698		if err := os.WriteFile(claudePath, []byte(claudeContent), 0644); err != nil {
699			return nil, fmt.Errorf("failed to write CLAUDE.md: %w", err)
700		}
701	
702		return loadedPersonas, nil
703	}
