709	// parsePersonaMetadata parses YAML frontmatter from persona content
710	func parsePersonaMetadata(content string) *PersonaMetadata {
711		lines := strings.Split(content, "\n")
712		if len(lines) == 0 || lines[0] != "---" {
713			return nil
714		}
715	
716		// Find end of frontmatter
717		endIdx := -1
718		for i := 1; i < len(lines); i++ {
719			if lines[i] == "---" {
720				endIdx = i
721				break
722			}
723		}
724	
725		if endIdx == -1 {
726			return nil
727		}
728	
729		// Parse YAML frontmatter
730		frontmatter := strings.Join(lines[1:endIdx], "\n")
731		var metadata PersonaMetadata
732		if err := yaml.Unmarshal([]byte(frontmatter), &metadata); err != nil {
733			return nil
734		}
735	
736		return &metadata
737	}
738	
739	// validatePersonaContent validates persona content structure
740	func validatePersonaContent(content, personaName string) error {
741		if strings.HasPrefix(content, "---\n") {
742			// Try to parse the frontmatter to validate it
743			lines := strings.Split(content, "\n")
744			endIdx := -1
745			for i := 1; i < len(lines); i++ {
746				if lines[i] == "---" {
747					endIdx = i
748					break
749				}
750			}
751			if endIdx > 0 {
752				frontmatter := strings.Join(lines[1:endIdx], "\n")
753				var metadata PersonaMetadata
754				if err := yaml.Unmarshal([]byte(frontmatter), &metadata); err != nil {
755					return fmt.Errorf("failed to parse YAML frontmatter in persona '%s': %w", personaName, err)
756				}
757			}
758		}
759		return nil
760	}
