812	// addPersonaBindingToNode adds or updates a persona binding in a YAML node tree
813	func addPersonaBindingToNode(rootNode *yaml.Node, role, personaName string) error {
814		// Find the document node
815		var docNode *yaml.Node
816		if rootNode.Kind == yaml.DocumentNode && len(rootNode.Content) > 0 {
817			docNode = rootNode.Content[0]
818		} else if rootNode.Kind == yaml.MappingNode {
819			docNode = rootNode
820		} else {
821			return fmt.Errorf("invalid YAML structure")
822		}
823	
824		if docNode.Kind != yaml.MappingNode {
825			return fmt.Errorf("root node is not a mapping")
826		}
827	
828		// Look for existing persona_bindings key
829		for i := 0; i < len(docNode.Content); i += 2 {
830			keyNode := docNode.Content[i]
831			if keyNode.Value == "persona_bindings" {
832				// Found existing persona_bindings, update it
833				valueNode := docNode.Content[i+1]
834				if valueNode.Kind != yaml.MappingNode {
835					// Convert to mapping node
836					valueNode.Kind = yaml.MappingNode
837					valueNode.Content = []*yaml.Node{}
838				}
839	
840				// Look for existing role or add new one
841				found := false
842				for j := 0; j < len(valueNode.Content); j += 2 {
843					roleKeyNode := valueNode.Content[j]
844					if roleKeyNode.Value == role {
845						// Update existing role
846						valueNode.Content[j+1].Value = personaName
847						found = true
848						break
849					}
850				}
851	
852				if !found {
853					// Add new role-persona pair
854					roleKeyNode := &yaml.Node{
855						Kind:  yaml.ScalarNode,
856						Value: role,
857					}
858					personaValueNode := &yaml.Node{
859						Kind:  yaml.ScalarNode,
860						Value: personaName,
861					}
862					valueNode.Content = append(valueNode.Content, roleKeyNode, personaValueNode)
863				}
864				return nil
865			}
866		}
867	
868		// persona_bindings key not found, add it
869		bindingsKeyNode := &yaml.Node{
870			Kind:  yaml.ScalarNode,
871			Value: "persona_bindings",
872		}
873	
874		roleKeyNode := &yaml.Node{
875			Kind:  yaml.ScalarNode,
876			Value: role,
877		}
878		personaValueNode := &yaml.Node{
879			Kind:  yaml.ScalarNode,
880			Value: personaName,
881		}
882	
883		bindingsValueNode := &yaml.Node{
884			Kind:    yaml.MappingNode,
885			Content: []*yaml.Node{roleKeyNode, personaValueNode},
886		}
887	
888		docNode.Content = append(docNode.Content, bindingsKeyNode, bindingsValueNode)
889	
890		return nil
891	}
