107	func (r *mutationResolver) ComparisonDispatch(ctx context.Context, arms []*ComparisonArmInput) (*ComparisonDispatchResult, error) {
108		if len(arms) == 0 {
109			return nil, fmt.Errorf("comparison requires at least one arm")
110		}
111		for i, arm := range arms {
112			if arm == nil {
113				return nil, fmt.Errorf("comparison arm %d is required", i)
114			}
115			arm.Model = strings.TrimSpace(arm.Model)
116			arm.Prompt = strings.TrimSpace(arm.Prompt)
117			if arm.Model == "" {
118				return nil, fmt.Errorf("comparison arm %d model is required", i)
119			}
120			if arm.Prompt == "" {
121				return nil, fmt.Errorf("comparison arm %d prompt is required", i)
122			}
123			if arm.Harness != nil {
