125				arm.Harness = &trimmed
126			}
127			if arm.Provider != nil {
128				trimmed := strings.TrimSpace(*arm.Provider)
129				arm.Provider = &trimmed
130			}
131		}
132	
133		id := newDispatchID("comparison")
134		record := comparisonDispatchRecord{
135			ID:        id,
136			State:     queuedPlaceholderState,
137			ArmCount:  len(arms),
138			Arms:      arms,
139			CreatedAt: time.Now().UTC(),
140		}
141		if err := writeJSONRecord(r.WorkingDir, "comparisons", id, record); err != nil {
142			return nil, err
143		}
144		return &ComparisonDispatchResult{
145			ID:       id,
146			State:    queuedPlaceholderState,
147			ArmCount: len(arms),
148		}, nil
149	}
