261	// PaletteSearch is the resolver for the paletteSearch field.
262	func (r *queryResolver) PaletteSearch(ctx context.Context, query string) (*PaletteSearchResults, error) {
263		q := strings.TrimSpace(query)
264		out := &PaletteSearchResults{
265			Documents:  []*PaletteDocumentResult{},
266			Beads:      []*PaletteBeadResult{},
267			Actions:    []*PaletteActionResult{},
268			Navigation: []*PaletteNavigationResult{},
269		}
270		if q == "" {
271			return out, nil
272		}
273	
274		matches := collectPaletteMatches(q, r.WorkingDir)
275		sort.SliceStable(matches, func(i, j int) bool {
276			if matches[i].score != matches[j].score {
277				return matches[i].score < matches[j].score
278			}
279			return matches[i].sortKey < matches[j].sortKey
280		})
281		if len(matches) > paletteResultCap {
282			matches = matches[:paletteResultCap]
283		}
284		for _, match := range matches {
285			switch match.kind {
286			case "document":
287				out.Documents = append(out.Documents, &PaletteDocumentResult{Kind: "document", Path: match.id, Title: match.title})
288			case "bead":
289				out.Beads = append(out.Beads, &PaletteBeadResult{Kind: "bead", ID: match.id, Title: match.title})
290			case "action":
291				out.Actions = append(out.Actions, &PaletteActionResult{Kind: "action", ID: match.id, Label: match.title})
292			case "nav":
293				out.Navigation = append(out.Navigation, &PaletteNavigationResult{Kind: "nav", Route: match.id, Title: match.title})
294			}
295		}
296		return out, nil
297	}
