325	func dispatchPluginAction(workingDir string, name string, action string) (string, error) {
326		state, err := registry.LoadState()
327		if err != nil {
328			return "", fmt.Errorf("loading plugin state: %w", err)
329		}
330	
331		switch action {
332		case "install":
333			if entry := state.FindInstalled(name); entry != nil && entry.VerifyFiles() {
334				return "installed", nil
335			}
336			entry, err := installRegistryPlugin(workingDir, state, name)
337			if err != nil {
338				return "", err
339			}
340			if entry != nil && entry.VerifyFiles() {
341				return "installed", nil
342			}
343			return "", fmt.Errorf("plugin %q install completed but recorded files are not present", name)
344		case "update":
345			installed := state.FindInstalled(name)
346			if installed == nil {
347				return "", fmt.Errorf("plugin %q is not installed", name)
348			}
349			pkg, err := registry.BuiltinRegistry().Find(name)
350			if err != nil {
351				return "", fmt.Errorf("plugin %q is not updateable from the built-in registry", name)
352			}
353			if installed.Version == pkg.Version && installed.VerifyFiles() {
354				return "installed", nil
355			}
356			entry, err := installRegistryPlugin(workingDir, state, name)
357			if err != nil {
358				return "", err
359			}
360			if entry != nil && entry.VerifyFiles() {
361				return "installed", nil
362			}
363			return "", fmt.Errorf("plugin %q update completed but recorded files are not present", name)
364		case "uninstall":
365			entry := state.FindInstalled(name)
366			if entry == nil {
367				return "", fmt.Errorf("plugin %q is not installed", name)
368			}
369			if err := registry.UninstallPackage(entry); err != nil {
370				return "", err
371			}
372			state.Remove(name)
373			if err := registry.SaveState(state); err != nil {
374				return "", fmt.Errorf("saving plugin state: %w", err)
375			}
376			return "uninstalled", nil
377		default:
378			return "", fmt.Errorf("unsupported plugin action %q", action)
379		}
380	}
381	
382	func installRegistryPlugin(workingDir string, state *registry.InstalledState, name string) (*registry.InstalledEntry, error) {
383		pkg, err := registry.BuiltinRegistry().Find(name)
384		if err != nil {
385			return nil, err
386		}
387	
388		origDir, _ := os.Getwd()
389		if workingDir != "" && origDir != workingDir {
390			if err := os.Chdir(workingDir); err != nil {
391				return nil, fmt.Errorf("entering project root: %w", err)
392			}
393			defer func() { _ = os.Chdir(origDir) }()
394		}
395	
396		entry, err := registry.InstallPackage(pkg)
397		if err != nil {
398			return nil, fmt.Errorf("installing plugin %q: %w", name, err)
399		}
400		state.AddOrUpdate(entry)
401		if err := registry.SaveState(state); err != nil {
402			return nil, fmt.Errorf("saving plugin state: %w", err)
403		}
404		return state.FindInstalled(name), nil
405	}
