407	func readComparisonRecords(workingDir string) ([]comparisonDispatchRecord, error) {
408		dir := filepath.Join(workingDir, ".ddx", "comparisons")
409		entries, err := os.ReadDir(dir)
410		if os.IsNotExist(err) {
411			return []comparisonDispatchRecord{}, nil
412		}
413		if err != nil {
414			return nil, err
415		}
416		records := make([]comparisonDispatchRecord, 0, len(entries))
417		for _, entry := range entries {
418			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
419				continue
420			}
421			data, err := os.ReadFile(filepath.Join(dir, entry.Name()))
422			if err != nil {
423				return nil, err
424			}
425			var record comparisonDispatchRecord
426			if err := json.Unmarshal(data, &record); err != nil {
427				return nil, fmt.Errorf("parsing comparison record %s: %w", entry.Name(), err)
428			}
429			if record.ID == "" {
430				continue
431			}
432			records = append(records, record)
433		}
434		sort.Slice(records, func(i, j int) bool {
435			if !records[i].CreatedAt.Equal(records[j].CreatedAt) {
436				return records[i].CreatedAt.After(records[j].CreatedAt)
437			}
438			return records[i].ID < records[j].ID
439		})
440		return records, nil
441	}
