456	func newDispatchID(prefix string, parts ...string) string {
457		segments := []string{slug(prefix)}
458		for _, part := range parts {
459			if s := slug(part); s != "" {
460				segments = append(segments, s)
461			}
462		}
463		segments = append(segments, randomHex(4))
464		return strings.Join(segments, "-")
465	}
