475	func pluginCatalog(workingDir string) ([]*PluginInfo, error) {
476		reg := registry.BuiltinRegistry()
477		state, err := registry.LoadState()
478		if err != nil {
479			return nil, err
480		}
481	
482		byName := map[string]*PluginInfo{}
483		installedByName := map[string]registry.InstalledEntry{}
484		for _, entry := range state.Installed {
485			installedByName[entry.Name] = entry
486		}
487	
488		for _, pkg := range reg.Packages {
489			info := pluginInfoFromPackage(pkg, workingDir, installedByName[pkg.Name])
490			byName[info.Name] = info
491		}
492		for _, entry := range state.Installed {
493			if _, ok := byName[entry.Name]; ok {
494				continue
495			}
496			info := pluginInfoFromInstalled(entry, workingDir)
497			byName[info.Name] = info
498		}
499	
500		out := make([]*PluginInfo, 0, len(byName))
501		for _, info := range byName {
502			out = append(out, info)
503		}
504		sort.Slice(out, func(i, j int) bool { return out[i].Name < out[j].Name })
505		return out, nil
506	}
