508	func pluginInfoFromPackage(pkg registry.Package, workingDir string, installed registry.InstalledEntry) *PluginInfo {
509		info := &PluginInfo{
510			Name:           pkg.Name,
511			Version:        pkg.Version,
512			Type:           string(pkg.Type),
513			Description:    pkg.Description,
514			Keywords:       append([]string(nil), pkg.Keywords...),
515			Status:         "available",
516			RegistrySource: pkg.Source,
517			Skills:         []string{},
518			Prompts:        []string{},
519			Templates:      []string{},
520		}
521		if installed.Name != "" {
522			info.InstalledVersion = strPtr(installed.Version)
523			info.Status = "installed"
524			if installed.Version != "" && installed.Version != pkg.Version {
525				info.Status = "update-available"
526			}
527		}
528		if manifest, err := json.Marshal(pkg); err == nil {
529			info.Manifest = strPtr(string(manifest))
530		}
531		enrichPluginInfoFromDisk(info, workingDir, pkg.Name, installed)
532		return info
