552	func enrichPluginInfoFromDisk(info *PluginInfo, workingDir string, name string, entry registry.InstalledEntry) {
553		for _, root := range pluginRootCandidates(workingDir, name, entry) {
554			if root == "" {
555				continue
556			}
557			if stat, err := os.Stat(root); err != nil || !stat.IsDir() {
558				continue
559			}
560			if info.DiskBytes == 0 {
561				info.DiskBytes = dirSize(root)
562			}
563			if pkg, _, err := registry.LoadPackageManifest(root); err == nil && pkg != nil {
564				if pkg.Version != "" {
565					info.Version = pkg.Version
566				}
567				if pkg.Description != "" {
568					info.Description = pkg.Description
569				}
570				if pkg.Type != "" {
571					info.Type = string(pkg.Type)
572				}
573				if pkg.Source != "" {
574					info.RegistrySource = pkg.Source
575				}
576				if len(pkg.Keywords) > 0 {
577					info.Keywords = append([]string(nil), pkg.Keywords...)
578				}
579				if manifest, err := json.Marshal(pkg); err == nil {
580					info.Manifest = strPtr(string(manifest))
581				}
582			}
583			info.Skills = uniqueStrings(append(info.Skills, scanNamedChildren(root, []string{"skills", ".agents/skills", ".claude/skills"}, "SKILL.md")...))
584			info.Prompts = uniqueStrings(append(info.Prompts, scanNamedChildren(root, []string{"prompts", "library/prompts"}, "")...))
585			info.Templates = uniqueStrings(append(info.Templates, scanNamedChildren(root, []string{"templates", "library/templates"}, "")...))
586		}
587	}
