589	func pluginRootCandidates(workingDir string, name string, entry registry.InstalledEntry) []string {
590		var roots []string
591		if workingDir != "" {
592			roots = append(roots, filepath.Join(workingDir, ".ddx", "plugins", name))
593		}
594		roots = append(roots, registry.ExpandHome(filepath.Join("~", ".ddx", "plugins", name)))
595		for _, f := range entry.Files {
596			expanded := registry.ExpandHome(f)
597			if expanded == "" {
598				continue
599			}
600			roots = append(roots, pluginRootFromRecordedFile(expanded, name))
601		}
602		return uniqueStrings(roots)
603	}
604	
605	func pluginRootFromRecordedFile(path string, name string) string {
606		cleaned := filepath.Clean(path)
607		if filepath.Base(cleaned) == name {
608			return cleaned
609		}
610		for dir := cleaned; dir != "." && dir != string(filepath.Separator); dir = filepath.Dir(dir) {
611			if filepath.Base(dir) == name && filepath.Base(filepath.Dir(dir)) == "plugins" {
612				return dir
613			}
614			next := filepath.Dir(dir)
615			if next == dir {
616				break
617			}
618		}
619		return cleaned
620	}
621	
622	func dirSize(root string) int {
623		var total int64
624		_ = filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
625			if err != nil || d.IsDir() {
626				return nil
627			}
628			if info, err := d.Info(); err == nil {
629				total += info.Size()
630			}
631			return nil
632		})
633		const maxInt32 = int64(1<<31 - 1)
634		if total > maxInt32 {
635			return int(maxInt32)
636		}
637		return int(total)
638	}
639	
640	func scanNamedChildren(root string, relDirs []string, marker string) []string {
641		var out []string
642		for _, rel := range relDirs {
643			base := filepath.Join(root, filepath.FromSlash(rel))
644			entries, err := os.ReadDir(base)
645			if err != nil {
646				continue
647			}
648			for _, entry := range entries {
649				if strings.HasPrefix(entry.Name(), ".") {
650					continue
651				}
652				if marker != "" {
653					if !entry.IsDir() {
654						continue
655					}
656					if _, err := os.Stat(filepath.Join(base, entry.Name(), marker)); err != nil {
657						continue
658					}
659				}
660				out = append(out, entry.Name())
661			}
662		}
663		return out
664	}
