671	type sessionEfficacyCacheEntry struct {
672		fingerprint string
673		snapshot    efficacySnapshot
674	}
675	
676	var sessionEfficacyCache struct {
677		sync.Mutex
678		byQuery map[string]sessionEfficacyCacheEntry
679	}
680	
681	func (r *queryResolver) efficacySnapshot(since, until, projectID *string) (efficacySnapshot, error) {
682		projectRoot := r.WorkingDir
683		if projectID != nil && strings.TrimSpace(*projectID) != "" {
684			projectRoot = r.projectRoot(strings.TrimSpace(*projectID))
685		}
686		startedAfter, err := parseOptionalEfficacyTime("since", since)
687		if err != nil {
688			return efficacySnapshot{}, err
689		}
690		startedBefore, err := parseOptionalEfficacyTime("until", until)
691		if err != nil {
692			return efficacySnapshot{}, err
693		}
694		logDir := agent.SessionLogDirForWorkDir(projectRoot)
695		query := agent.SessionIndexQuery{
696			StartedAfter:  startedAfter,
697			StartedBefore: startedBefore,
698		}
699		cacheKey := sessionEfficacyCacheKey(logDir, startedAfter, startedBefore)
700		fingerprint, err := sessionEfficacyIndexFingerprint(logDir, query)
701		if err != nil {
702			return efficacySnapshot{}, err
703		}
704		sessionEfficacyCache.Lock()
705		if sessionEfficacyCache.byQuery == nil {
706			sessionEfficacyCache.byQuery = map[string]sessionEfficacyCacheEntry{}
707		}
708		if cached, ok := sessionEfficacyCache.byQuery[cacheKey]; ok && cached.fingerprint == fingerprint {
709			sessionEfficacyCache.Unlock()
710			return cached.snapshot, nil
711		}
712		sessionEfficacyCache.Unlock()
713	
714		entries, err := agent.ReadSessionIndex(logDir, query)
715		if err != nil {
716			return efficacySnapshot{}, err
717		}
718		snap := buildEfficacySnapshotFromSessionEntries(entries)
719		sessionEfficacyCache.Lock()
720		sessionEfficacyCache.byQuery[cacheKey] = sessionEfficacyCacheEntry{fingerprint: fingerprint, snapshot: snap}
721		sessionEfficacyCache.Unlock()
722		return snap, nil
723	}
724	
725	func sessionEfficacyCacheKey(logDir string, startedAfter, startedBefore *time.Time) string {
726		return strings.Join([]string{logDir, timeKey(startedAfter), timeKey(startedBefore)}, "|")
727	}
728	
729	func timeKey(t *time.Time) string {
730		if t == nil {
731			return ""
732		}
733		return t.UTC().Format(time.RFC3339Nano)
734	}
735	
736	func sessionEfficacyIndexFingerprint(logDir string, query agent.SessionIndexQuery) (string, error) {
737		files, err := agent.SessionIndexShardFiles(logDir, query)
738		if err != nil {
739			return "", err
740		}
741		parts := make([]string, 0, len(files))
742		for _, file := range files {
743			info, err := os.Stat(file)
744			if os.IsNotExist(err) {
745				continue
746			}
747			if err != nil {
748				return "", err
749			}
750			parts = append(parts, fmt.Sprintf("%s:%d:%d", file, info.Size(), info.ModTime().UnixNano()))
751		}
752		return strings.Join(parts, "|"), nil
753	}
754	
755	func parseOptionalEfficacyTime(name string, raw *string) (*time.Time, error) {
756		if raw == nil || strings.TrimSpace(*raw) == "" {
757			return nil, nil
758		}
759		value := strings.TrimSpace(*raw)
760		for _, layout := range []string{time.RFC3339Nano, time.RFC3339, "2006-01-02"} {
761			if parsed, err := time.Parse(layout, value); err == nil {
762				utc := parsed.UTC()
763				return &utc, nil
764			}
765		}
766		return nil, fmt.Errorf("%s must be RFC3339 or YYYY-MM-DD, got %q", name, value)
767	}
