784	func buildEfficacySnapshotFromSessionEntries(entries []agent.SessionIndexEntry) efficacySnapshot {
785		grouped := map[string][]sessionEfficacyAttempt{}
786		for _, entry := range entries {
787			attempt := efficacyAttemptFromSession(entry)
788			if attempt.RowKey == "" {
789				continue
790			}
791			grouped[attempt.RowKey] = append(grouped[attempt.RowKey], attempt)
792		}
793		rows := make([]*EfficacyRow, 0, len(grouped))
794		attemptDetails := map[string][]*EfficacyAttempt{}
795		for rowKey, group := range grouped {
796			sort.Slice(group, func(i, j int) bool { return group[i].CreatedAt.After(group[j].CreatedAt) })
797			attemptDetails[rowKey] = make([]*EfficacyAttempt, 0, len(group))
798			var inputTokens, outputTokens, durations []int
799			var costs []float64
800			var successes int
801			for _, attempt := range group {
802				if attempt.Outcome == "succeeded" {
803					successes++
804				}
805				inputTokens = append(inputTokens, attempt.InputTokens)
806				outputTokens = append(outputTokens, attempt.OutputTokens)
807				durations = append(durations, attempt.DurationMs)
808				if attempt.CostUsd != nil {
809					costs = append(costs, *attempt.CostUsd)
810				}
811				attemptDetails[rowKey] = append(attemptDetails[rowKey], &EfficacyAttempt{
812					BeadID:            attempt.BeadID,
813					Outcome:           attempt.Outcome,
814					DurationMs:        attempt.DurationMs,
815					CostUsd:           attempt.CostUsd,
816					EvidenceBundleURL: attempt.EvidencePath,
817				})
818			}
819			parts := strings.Split(rowKey, "|")
820			row := &EfficacyRow{
821				RowKey:             rowKey,
822				Harness:            parts[0],
823				Provider:           parts[1],
824				Model:              parts[2],
825				Attempts:           len(group),
826				Successes:          successes,
827				SuccessRate:        float64(successes) / float64(len(group)),
828				MedianInputTokens:  medianInt(inputTokens),
829				MedianOutputTokens: medianInt(outputTokens),
830				MedianDurationMs:   medianInt(durations),
831				MedianCostUsd:      medianFloatPtr(costs),
832			}
833			if row.SuccessRate < efficacyWarningFloor {
834				row.Warning = &EfficacyWarning{Kind: "below-adaptive-floor", Threshold: floatPtr(efficacyWarningFloor)}
835			}
836			rows = append(rows, row)
837		}
838		sort.Slice(rows, func(i, j int) bool {
839			if rows[i].SuccessRate != rows[j].SuccessRate {
840				return rows[i].SuccessRate > rows[j].SuccessRate
841			}
842			return rows[i].RowKey < rows[j].RowKey
843		})
844	
845		return efficacySnapshot{rows: rows, attempts: attemptDetails}
846	}
