848	func efficacyAttemptFromSession(entry agent.SessionIndexEntry) sessionEfficacyAttempt {
849		model := firstNonEmpty(entry.Model, "unknown")
850		provider := firstNonEmpty(entry.Provider, providerFromModel(model), entry.Harness, "unknown")
851		harness := firstNonEmpty(entry.Harness, provider, "unknown")
852		cost := efficacyCost(entry)
853		outcome := efficacyOutcome(entry)
854		return sessionEfficacyAttempt{
855			RowKey:       strings.Join([]string{harness, provider, model}, "|"),
856			BeadID:       entry.BeadID,
857			Outcome:      outcome,
858			Harness:      harness,
859			Provider:     provider,
860			Model:        model,
861			InputTokens:  entry.InputTokens,
862			OutputTokens: entry.OutputTokens,
863			DurationMs:   entry.DurationMS,
864			CostUsd:      cost,
865			EvidencePath: efficacyEvidencePath(entry),
866			CreatedAt:    entry.StartedAt,
867		}
868	}
