885	func efficacyOutcome(entry agent.SessionIndexEntry) string {
886		switch strings.ToLower(strings.TrimSpace(entry.Outcome)) {
887		case "success", "succeeded", "ok", "passed":
888			return "succeeded"
889		case "failure", "failed", "error", "timed_out", "timeout", "cancelled", "stalled":
890			return "failed"
891		}
892		if entry.ExitCode == 0 && entry.Detail == "" {
893			return "succeeded"
894		}
895		return "failed"
896	}
