919	func collectPaletteMatches(query string, workingDir string) []paletteMatch {
920		var out []paletteMatch
921		if graph, err := docgraph.BuildGraphWithConfig(workingDir); err == nil {
922			for _, doc := range graph.AllNodesForOutput() {
923				if score, ok := paletteScore(query, doc.Path, doc.Title); ok {
924					out = append(out, paletteMatch{
925						kind:    "document",
926						id:      filepath.ToSlash(doc.Path),
927						title:   doc.Title,
928						score:   score,
929						sortKey: "document:" + doc.Path,
930					})
931				}
932			}
933		}
934	
935		store := bead.NewStore(filepath.Join(workingDir, ".ddx"))
936		if beads, err := store.ReadAll(); err == nil {
937			for _, b := range beads {
938				if score, ok := paletteScore(query, b.ID, b.Title); ok {
939					out = append(out, paletteMatch{kind: "bead", id: b.ID, title: b.Title, score: score, sortKey: "bead:" + b.ID})
940				}
941			}
942		}
943	
944		for _, action := range []struct{ id, label string }{
945			{"drain-queue", "Drain queue"},
946			{"realign-specs", "Re-align specs"},
947			{"run-checks", "Run checks"},
948		} {
949			if score, ok := paletteScore(query, action.id, action.label); ok {
950				out = append(out, paletteMatch{kind: "action", id: action.id, title: action.label, score: score, sortKey: "action:" + action.id})
951			}
952		}
953		for _, nav := range []struct{ route, title string }{
954			{"/beads", "Beads"},
955			{"/documents", "Documents"},
956			{"/graph", "Graph"},
957			{"/workers", "Workers"},
958			{"/personas", "Personas"},
959			{"/plugins", "Plugins"},
960			{"/efficacy", "Efficacy"},
961		} {
962			if score, ok := paletteScore(query, nav.route, nav.title); ok {
963				out = append(out, paletteMatch{kind: "nav", id: nav.route, title: nav.title, score: score, sortKey: "nav:" + nav.route})
964			}
965		}
966		return out
967	}
