969	func paletteScore(query string, fields ...string) (int, bool) {
970		q := strings.ToLower(strings.TrimSpace(query))
971		if q == "" {
972			return 0, false
973		}
974		terms := strings.Fields(q)
975		best := 1000
976		for _, field := range fields {
977			f := strings.ToLower(field)
978			if strings.HasPrefix(f, q) {
979				best = min(best, 0)
980				continue
981			}
982			for _, part := range strings.FieldsFunc(f, func(r rune) bool {
983				return r == '/' || r == '-' || r == '_' || r == '.' || r == ' ' || r == ':'
984			}) {
985				if strings.HasPrefix(part, q) {
986					best = min(best, 1)
987				}
988			}
989			allTerms := true
990			for _, term := range terms {
991				if !strings.Contains(f, term) {
992					allTerms = false
993					break
994				}
995			}
996			if allTerms {
997				best = min(best, 2)
998			}
999		}
1000		if best == 1000 {
1001			return 0, false
1002		}
1003		return best, true
1004	}
