1006	func medianInt(values []int) int {
1007		if len(values) == 0 {
1008			return 0
1009		}
1010		sort.Ints(values)
1011		return values[len(values)/2]
1012	}
1013	
1014	func medianFloatPtr(values []float64) *float64 {
1015		if len(values) == 0 {
1016			return nil
1017		}
1018		sort.Float64s(values)
1019		v := values[len(values)/2]
1020		return &v
1021	}
1022	
1023	func firstNonEmpty(values ...string) string {
1024		for _, value := range values {
1025			if strings.TrimSpace(value) != "" {
1026				return strings.TrimSpace(value)
1027			}
1028		}
1029		return ""
1030	}
1031	
1032	func uniqueStrings(values []string) []string {
1033		seen := map[string]bool{}
1034		var out []string
1035		for _, value := range values {
1036			value = strings.TrimSpace(value)
1037			if value == "" || seen[value] {
1038				continue
1039			}
1040			seen[value] = true
1041			out = append(out, value)
1042		}
1043		sort.Strings(out)
1044		return out
1045	}
1046	
1047	func strPtr(v string) *string {
1048		return &v
1049	}
1050	
1051	func floatPtr(v float64) *float64 {
1052		return &v
1053	}
1054	
1055	func slug(v string) string {
1056		v = strings.ToLower(strings.TrimSpace(v))
1057		v = strings.ReplaceAll(v, "_", "-")
1058		v = strings.ReplaceAll(v, " ", "-")
1059		return v
1060	}
