56	func personaToGQL(p *persona.Persona) *Persona {
57		return &Persona{
58			ID:          "persona-" + p.Name,
59			Name:        p.Name,
60			Roles:       p.Roles,
61			Description: p.Description,
62			Tags:        p.Tags,
63			Content:     p.Content,
64			Body:        p.Content,
