70	func personaConnectionFrom(personas []*Persona, first *int, after *string, last *int, before *string) *PersonaConnection {
71		all := make([]*PersonaEdge, len(personas))
72		ids := make([]string, len(personas))
73		for i, p := range personas {
74			all[i] = &PersonaEdge{Node: p, Cursor: encodeStableCursor(p.ID)}
75			ids[i] = p.ID
76		}
77		startIdx, endIdx := stablePageBounds(ids, after, before)
78		slice := all[startIdx:endIdx]
79		truncByFirst, truncByLast := false, false
80		if first != nil && *first >= 0 && *first < len(slice) {
81			slice = slice[:*first]
82			truncByFirst = true
83		}
84		if last != nil && *last >= 0 && *last < len(slice) {
85			slice = slice[len(slice)-*last:]
86			truncByLast = true
87		}
88		pageInfo := &PageInfo{
89			HasPreviousPage: startIdx > 0 || truncByLast,
90			HasNextPage:     endIdx < len(all) || truncByFirst,
91		}
92		if len(slice) > 0 {
93			pageInfo.StartCursor = &slice[0].Cursor
94			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
95		}
96		return &PersonaConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
97	}
