12	// BindingManagerImpl implements the BindingManager interface
13	type BindingManagerImpl struct {
14		configPath string
15	}
16	
17	// NewBindingManager creates a new binding manager with the default config path
18	func NewBindingManager() BindingManager {
19		return &BindingManagerImpl{
20			configPath: ConfigFileName, // ".ddx.yml" in current directory
21		}
22	}
23	
24	// NewBindingManagerWithPath creates a new binding manager with a specific config path
25	func NewBindingManagerWithPath(configPath string) BindingManager {
26		return &BindingManagerImpl{
27			configPath: configPath,
28		}
29	}
30	
31	// GetBinding returns the persona bound to the specified role
32	func (b *BindingManagerImpl) GetBinding(role string) (string, error) {
33		if strings.TrimSpace(role) == "" {
34			return "", NewPersonaError(ErrorValidation, "role cannot be empty", nil)
35		}
36	
37		config, err := b.loadConfig()
38		if err != nil {
39			// Return the error so CLI can handle it
40			return "", err
41		}
42	
43		if config.Bindings == nil {
44			return "", nil
45		}
46	
47		persona, exists := config.Bindings[role]
48		if !exists {
49			return "", nil
50		}
51	
52		return persona, nil
53	}
54	
55	// SetBinding binds a persona to a role
56	func (b *BindingManagerImpl) SetBinding(role, persona string) error {
57		if strings.TrimSpace(role) == "" {
58			return NewPersonaError(ErrorValidation, "role cannot be empty", nil)
59		}
60		if strings.TrimSpace(persona) == "" {
61			return NewPersonaError(ErrorValidation, "persona cannot be empty", nil)
62		}
63	
64		// Load existing config or create new one
65		var config map[string]interface{}
66	
67		if fileExists(b.configPath) {
68			content, err := os.ReadFile(b.configPath)
69			if err != nil {
70				return NewPersonaError(ErrorFileOperation,
71					fmt.Sprintf("failed to read config file %s", b.configPath), err)
72			}
73	
74			if err := yaml.Unmarshal(content, &config); err != nil {
75				return NewPersonaError(ErrorInvalidConfig,
76					fmt.Sprintf("failed to parse config file %s", b.configPath), err)
77			}
78		} else {
79			config = make(map[string]interface{})
80		}
81	
82		// Ensure persona_bindings section exists
83		bindings, exists := config["persona_bindings"]
84		if !exists {
85			bindings = make(map[string]interface{})
86			config["persona_bindings"] = bindings
87		}
88	
89		// Convert to map if needed
90		bindingsMap, ok := bindings.(map[string]interface{})
91		if !ok {
92			bindingsMap = make(map[string]interface{})
93			config["persona_bindings"] = bindingsMap
94		}
95	
96		// Set the binding
97		bindingsMap[role] = persona
98	
99		// Save config
100		return b.saveConfig(config)
101	}
102	
103	// GetAllBindings returns all current role-persona bindings
104	func (b *BindingManagerImpl) GetAllBindings() (map[string]string, error) {
105		config, err := b.loadConfig()
106		if err != nil {
107			// Return the error so CLI can handle it
108			return nil, err
109		}
110	
111		if config.Bindings == nil {
112			return make(map[string]string), nil
113		}
114	
115		// Return a copy to prevent modification
116		result := make(map[string]string)
117		for role, persona := range config.Bindings {
118			result[role] = persona
119		}
120	
121		return result, nil
122	}
123	
124	// RemoveBinding removes the binding for the specified role
125	func (b *BindingManagerImpl) RemoveBinding(role string) error {
126		if strings.TrimSpace(role) == "" {
127			return NewPersonaError(ErrorValidation, "role cannot be empty", nil)
128		}
129	
130		// Load existing config
131		if !fileExists(b.configPath) {
132			return nil // Nothing to remove
133		}
134	
135		content, err := os.ReadFile(b.configPath)
136		if err != nil {
137			return NewPersonaError(ErrorFileOperation,
138				fmt.Sprintf("failed to read config file %s", b.configPath), err)
139		}
140	
141		var config map[string]interface{}
142		if err := yaml.Unmarshal(content, &config); err != nil {
143			return NewPersonaError(ErrorInvalidConfig,
144				fmt.Sprintf("failed to parse config file %s", b.configPath), err)
145		}
146	
147		// Check if persona_bindings section exists
148		bindings, exists := config["persona_bindings"]
149		if !exists {
150			return nil // Nothing to remove
151		}
152	
153		bindingsMap, ok := bindings.(map[string]interface{})
154		if !ok {
155			return nil // Invalid bindings format, nothing to remove
156		}
157	
158		// Remove the binding
159		delete(bindingsMap, role)
160	
161		// If bindings is now empty, we can leave it (no need to remove the section)
162	
163		// Save config
164		return b.saveConfig(config)
165	}
