167	// GetOverride returns the persona override for a specific workflow and role
168	func (b *BindingManagerImpl) GetOverride(workflow, role string) (string, error) {
169		if strings.TrimSpace(workflow) == "" {
170			return "", NewPersonaError(ErrorValidation, "workflow cannot be empty", nil)
171		}
172		if strings.TrimSpace(role) == "" {
173			return "", NewPersonaError(ErrorValidation, "role cannot be empty", nil)
174		}
175	
176		config, err := b.loadConfig()
177		if err != nil {
178			// If config doesn't exist, return empty string (no override)
179			if os.IsNotExist(err) {
180				return "", nil
181			}
182			return "", err
183		}
184	
185		if config.Overrides == nil {
186			return "", nil
187		}
188	
189		workflowOverrides, exists := config.Overrides[workflow]
190		if !exists {
191			return "", nil
192		}
193	
194		persona, exists := workflowOverrides[role]
195		if !exists {
196			return "", nil
197		}
198	
199		return persona, nil
200	}
201	
202	// loadConfig loads the persona configuration from the config file
203	func (b *BindingManagerImpl) loadConfig() (*PersonaConfig, error) {
204		if !fileExists(b.configPath) {
205			return nil, os.ErrNotExist
206		}
207	
208		content, err := os.ReadFile(b.configPath)
209		if err != nil {
210			return nil, NewPersonaError(ErrorFileOperation,
211				fmt.Sprintf("failed to read config file %s", b.configPath), err)
212		}
213	
214		// Parse as generic map first to handle the full config structure
215		var fullConfig map[string]interface{}
216		if err := yaml.Unmarshal(content, &fullConfig); err != nil {
217			return nil, NewPersonaError(ErrorInvalidConfig,
218				fmt.Sprintf("failed to parse config file %s", b.configPath), err)
219		}
220	
221		// Extract persona configuration
222		var personaConfig PersonaConfig
223	
224		// Extract persona_bindings
225		if bindings, exists := fullConfig["persona_bindings"]; exists {
226			if bindingsMap, ok := bindings.(map[string]interface{}); ok {
227				personaConfig.Bindings = make(map[string]string)
228				for role, persona := range bindingsMap {
229					if personaStr, ok := persona.(string); ok {
230						personaConfig.Bindings[role] = personaStr
231					}
232				}
233			}
234		}
235	
236		// Extract overrides
237		if overrides, exists := fullConfig["overrides"]; exists {
238			if overridesMap, ok := overrides.(map[string]interface{}); ok {
239				personaConfig.Overrides = make(map[string]map[string]string)
240				for workflow, workflowOverrides := range overridesMap {
241					if workflowMap, ok := workflowOverrides.(map[string]interface{}); ok {
242						personaConfig.Overrides[workflow] = make(map[string]string)
243						for role, persona := range workflowMap {
244							if personaStr, ok := persona.(string); ok {
245								personaConfig.Overrides[workflow][role] = personaStr
246							}
247						}
248					}
249				}
250			}
251		}
252	
253		return &personaConfig, nil
254	}
255	
256	// saveConfig saves the configuration to the config file
257	func (b *BindingManagerImpl) saveConfig(config map[string]interface{}) error {
258		// Ensure the directory exists
259		dir := filepath.Dir(b.configPath)
260		if err := os.MkdirAll(dir, 0755); err != nil {
261			return NewPersonaError(ErrorFileOperation,
262				fmt.Sprintf("failed to create config directory %s", dir), err)
263		}
264	
265		// Marshal to YAML
266		content, err := yaml.Marshal(config)
267		if err != nil {
268			return NewPersonaError(ErrorInvalidConfig,
269				"failed to marshal config to YAML", err)
270		}
271	
272		// Write file
273		if err := os.WriteFile(b.configPath, content, 0644); err != nil {
274			return NewPersonaError(ErrorFileOperation,
275				fmt.Sprintf("failed to write config file %s", b.configPath), err)
276		}
277	
278		return nil
